import UIKit
import Foundation
import Alamofire

// Model for Stock
struct Stock: Codable {
    let symbol: String
    let name: String
    let price: Double
}

// Model for Trade
struct Trade: Identifiable, Codable {
    let id = UUID()
    var stock: Stock
    var quantity: Int
    var type: String // "buy" or "sell"
}

// Model for Portfolio
class Portfolio: ObservableObject {
    @Published var trades: [Trade] = []
    
    func add(trade: Trade) {
        trades.append(trade)
    }
    
    func remove(at offsets: IndexSet) {
        trades.remove(atOffsets: offsets)
    }
}

// API Manager for secure communication
class APIManager {
    static let shared = APIManager()
    
    func executeTrade(stock: Stock, quantity: Int, type: String, completion: @escaping (String?) -> Void) {
        guard let url = URL(string: "https://api.example.com/trades") else { return }
        
        var params: [String: Any] = [:]
        params["symbol"] = stock.symbol
        params["quantity"] = quantity
        
        AF.request(url, method: .post, parameters: params)
            .validate()
            .responseJSON(completionHandler: { response in
                switch response.result {
                case .success(let value):
                    let json = JSON(value)
                    print(json)
                    completion(nil)
                case .failure(let error):
                    print(error)
                    completion("Error executing trade")
                }
        })
    }
}

// Trade Manager for execution and portfolio management
class TradeManager: ObservableObject {
    @Published var portfolio: Portfolio = Portfolio()
    
    func executeTrade(stock: Stock, quantity: Int, type: String) {
        let trade = Trade(stock: stock, quantity: quantity, type: type)
        
        APIManager.shared.executeTrade(stock: stock, quantity: quantity, type: type) { error in
            if let error = error {
                print(error)
            } else {
                self.portfolio.add(trade: trade)
            }
        }
    }
}

// View Controller for trade execution and portfolio display
class TradeViewController: UIViewController {
    @IBOutlet weak var tableView: UITableView!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        self.navigationItem.title = "Trades"
        
        let stock1 = Stock(symbol: "AAPL", name: "Apple Inc.", price: 120.0)
        let tradeManager = TradeManager()
        tradeManager.executeTrade(stock: stock1, quantity: 10, type: "buy")
    }
}